import{_ as t,o as n,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"66. Individual Flexible Working Arrangements","description":"","frontmatter":{"title":"66. Individual Flexible Working Arrangements","eba":"Mental Health Services 2024-2028","topics":["leave","hours","overtime","flexible-work"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/workplace-rights/66-individual-flexible-working-arrangements.md","filePath":"ebas/mental-health/common-terms/workplace-rights/66-individual-flexible-working-arrangements.md"}'),o={name:"ebas/mental-health/common-terms/workplace-rights/66-individual-flexible-working-arrangements.md"};function i(s,e,l,g,p,m){return n(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_66-individual-flexible-working-arrangements" tabindex="-1">66. Individual Flexible Working Arrangements <a class="header-anchor" href="#_66-individual-flexible-working-arrangements" aria-label="Permalink to &quot;66. Individual Flexible Working Arrangements&quot;">​</a></h1><p><strong>66.1</strong> An Employer and Employee covered by this Agreement may agree to make an individual flexibility arrangement to vary the effect of terms of the Agreement if:</p><p><strong>(a)</strong> the arrangement deals with one (1) or more of the following matters:</p><p><strong>(i)</strong> when work is performed</p><p><strong>(ii)</strong> overtime rates</p><p><strong>(iii)</strong> penalty rates</p><p><strong>(iv)</strong> allowances; and/or</p><p><strong>(v)</strong> leave loading; and</p><p><strong>(b)</strong> the arrangement meets the genuine needs of the Employer and Employee in relation to one (1) or more of the matters mentioned in subclause 66.1(a); and</p><p><strong>(c)</strong> the arrangement is genuinely agreed by the Employer and Employee.</p><p><strong>66.2</strong> The Employee may appoint a representative for the purposes of the procedure in this clause 66, including the Union. Except as provided in subclause 66.5(c), the arrangement must not require the approval or consent of a person other than the Employer and the individual Employee.</p><p><strong>66.3</strong> The Employer must ensure that the terms of the individual flexibility arrangement:</p><p><strong>(a)</strong> are about permitted matters under section 172 of the Act</p><p><strong>(b)</strong> are not unlawful terms under section 194 of the Act; and</p><p><strong>(c)</strong> result in the Employee being better off overall than the Employee would be if no arrangement was made.</p><p><strong>66.4</strong> Where the Employee&#39;s understanding of written English is limited, the Employer will take measures, including translation into an appropriate language, to ensure the Employee understands the proposed individual flexibility arrangement.</p><p><strong>66.5</strong> The Employer must ensure that the individual flexibility arrangement:</p><p><strong>(a)</strong> is in writing</p><p><strong>(b)</strong> includes the name of the Employer and Employee</p><p><strong>(c)</strong> is signed by the Employer and the Employee and, if the Employee is under 18 years of age, the Employee&#39;s parent or guardian</p><p><strong>(d)</strong> includes details of:</p><p><strong>(i)</strong> the terms of the Agreement that will be varied by the arrangement</p><p><strong>(ii)</strong> how the arrangement will vary the effect of the terms; and</p><p><strong>(iii)</strong> how the Employee will be better off overall in relation to the terms and conditions of their employment as a result of the arrangement; and</p><p><strong>(e)</strong> states the date the arrangement commences.</p><p><strong>66.6</strong> The Employer must give the Employee a copy of the individual flexibility arrangement within 14 days after it is agreed to.</p><p><strong>66.7</strong> The Employer or Employee may terminate the individual flexibility arrangement:</p><p><strong>(a)</strong> by giving no more than 28 days&#39; written notice to the other party to the arrangement; or</p><p><strong>(b)</strong> if the Employer and Employee agree in writing - at any time.</p><p>Plain language terms: IFA, individual flex agreement.</p>',30)])])}const u=t(o,[["render",i]]);export{h as __pageData,u as default};
